    var level = hh.levelBuy, buy = hh.buy, sell = hh.sell;
    if (C.manual !== "auto") return { m: C.manual, r: "Manualni rezim, SOC " + Math.round(soc) + "%" };
    if (buy < 0) return { m: M.ZAP_NAK, r: (sell <= 0 ? "Zaporna nakup + bez exportu" : "Max. odber (zaporna nakup)") + ", SOC " + Math.round(soc) + "%" };
    if (sell <= 0) {
        if (x.cO[off]) return { m: M.NABIJET, r: "Nabijeni ze site (ZP, ultra levna), SOC " + Math.round(soc) + "%" };
        return { m: M.ZAKAZ, r: "Zakaz pretoku, SOC " + Math.round(soc) + "%" };
    }
    if (x.cO[off]) {
        if (x.aCO[off]) return { m: M.NABIJET, r: "Arbitraz -> " + x.aCO[off].targetHour + ":00, SOC " + Math.round(soc) + "%" };
        return { m: M.NABIJET, r: "Nabijeni ze site na " + Math.round(x.tSoc) + "%, SOC " + Math.round(soc) + "%" };
    }
    if (x.sellMap[off] && soc > x.sellTarget) {
        var rC = x.replCost(off), netSell = sell * C.dchEff - C.amort, profit = netSell - rC;
        return { m: M.PRODAVAT, r: "Prodej (zisk " + Math.round(profit * 10) / 10 + " Kc, replCost " + Math.round(rC * 100) / 100 + "), SOC " + Math.round(soc) + "%" };
    }
    if (isSol) {
        var nibeVPlan = (x.nibeK > 0 && level < C.DRAHA && nibeZbyva > 0 && nibeCD === 0);
        var nibePopis = nibeVPlan ? " (NIBE topi)" : "";
        if (level >= C.DRAHA && soc > C.minSoc) return { m: M.NORMAL, r: "Solarni + draha hodina" + nibePopis + ", SOC " + Math.round(soc) + "%" };
        return { m: M.NORMAL, r: "Solarni hodina" + nibePopis + ", SOC " + Math.round(soc) + "%" };
    }
    if (x.dO[off] && soc > C.minSoc) return { m: M.NORMAL, r: (level >= C.DRAHA ? "Draha hodina" : "Stredni cena") + ", SOC " + Math.round(soc) + "%" };
    if (soc <= C.minSoc) return { m: M.SETRIT, r: "Ochrana min. SOC, SOC " + Math.round(soc) + "%" };
    return { m: M.SETRIT, r: "Setrim baterii, SOC " + Math.round(soc) + "%" };
}

// Simulace SOC pro dany mod
function simulujSOC(mod, hour, soc, frac, level) {
    var jeSol = hour >= x.solS && hour < x.solE;
    if (mod === M.NABIJET) return Math.min(x.tSoc || 100, soc + (C.chKwh * frac * C.chEff / C.kap * 100));
    if (mod === M.PRODAVAT) return Math.max(x.sellTarget || C.minSoc, soc - (C.maxFeed / 1000 * frac / C.dchEff / C.kap * 100));
    if (mod === M.SETRIT) {
        if (jeSol) {
            var sk = solarKwh(hour), c = consAt(hour);
            return Math.min(100, soc + Math.max(0, ((sk - c) * frac * C.chEff / C.kap) * 100));
        }
        return soc;
    }
    if (mod === M.NORMAL) {
        if (jeSol) {
            var sk2 = solarKwh(hour), c2 = consAt(hour);
            return Math.min(100, Math.max(C.minSoc, soc + ((sk2 - c2) * frac * C.chEff / C.kap) * 100));
        }
        return Math.max(C.minSoc, soc - (consAt(hour) * frac / C.kap) * 100);
    }
    if (mod === M.ZAKAZ) return jeSol ? Math.min(100, soc + Math.max(0, (solarKwh(hour) - consAt(hour)) * frac * C.chEff / C.kap * 100)) : Math.max(C.minSoc, soc - (consAt(hour) * frac / C.kap) * 100);
    if (mod === M.ZAP_NAK) return Math.min(100, soc + (C.chKwh * frac * C.chEff / C.kap * 100));
    if (mod === M.BAL) return jeSol ? Math.min(100, soc + (C.chKwh * frac * C.chEff / C.kap * 100)) : soc;
    return soc;
}

var nazevModu = { normal: "Normalni provoz", setrit: "Setrit baterii", nabijet_ze_site: "Nabijet ze site", prodavat: "Prodavat do site", zakaz_pretoku: "Zakaz pretoku", "Balancování": "Balancovani baterie", zaporna_nakupni_cena: "Zaporny nakup" };
var plan = [], soc = x.cSoc;
for (var pi = 0; pi < hp.length; pi++) {
    var hod = hp[pi].hour, jPD = (x.cH + pi) >= 24, frac = pi === 0 ? x.fFrac : 1;
    var rz = resolveMode(pi, soc, frac);
    soc = simulujSOC(rz.m, hod, soc, frac, hp[pi].levelBuy);
    if (rz.r.indexOf("NIBE topi") > -1) { nibeZbyva--; nibeCD = 1; } else { nibeCD = Math.max(0, nibeCD - 1); }
    plan.push({
        hour: hod, offset: pi, mode: rz.m, modeCZ: nazevModu[rz.m] || rz.m, reason: rz.r,
        priceLevel: hp[pi].levelBuy, priceBuy: hp[pi].buy, priceSell: hp[pi].sell,
        simulatedSoc: Math.round(soc), isNextDay: jPD,
        isChargingHour: !!x.cO[pi], isSolarHour: !!x.sO[pi], isDischargeHour: !!x.dO[pi],
        isArbitrageCharge: !!x.aCO[pi], isArbitrageSell: !!x.aSO[pi],
        isBalancovani: rz.m === M.BAL, isPoolNibeHour: poolNibeH.includes(pi)
    });
}
x.plan = plan;
node.status({ fill: "green", shape: "dot", text: "Plan " + plan.length + "h SOC:" + x.cSoc + "->" + Math.round(soc) + "%" });
return msg;

